mapper.select:
SELECT TFBCP.ID "tfbcpId", TFBCP.PREPAYMENT_CODE "prepaymentCode", TFBCP.STATUS "prepaymentStatus", t.ID, t.SHIPVOYAGE_ID, t.SHIPVOYAGE_ITEM_ID, t.SCN, t.SHIP_NAME, t.CARGO_INFO_NO, t.CARGO_OWNER_ID, t.CARGO_OWNER_NAME, t.CARGO_AGENT_ID, t.CARGO_AGENT_NAME, t.CARGO_CODE, t.CARGO_NAME, t.TRADE_TYPE, t.PACKING_CODE, t.PACKING_NAME, t.COMPANY_ID, t.COMPANY_NAME, t.IS_CLEAR, t.VOYAGE, t.RESIDUE_STORAGE, t.TRANSFER_DATE, m.TALLY, t.CREATE_TIME, t.IS_PRE_PAY, t.IS_RELEASE, t.RELEASE_REMARK, CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END "shipNameVoyage", CASE WHEN t.IS_TOS IS NOT NULL THEN t.IS_TOS ELSE TBT.TYPE END "type", -- LISTAGG(TBT2.TRUST_NO, ',') WITHIN GROUP ( ORDER BY TBT2.TRUST_NO ) "trustNos", REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TBT2.TRUST_NO || ',') ORDER BY TBT2.TRUST_NO) AS CLOB), ','), '([^,]+)(,\1)+', '\1') AS "trustNos", m.WORK_TYPE, t.IS_LOGOUT, t.REAL_CLEAR_DATE FROM T_BUS_CARGO_INFO t LEFT JOIN T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP ON T.ID = TFBCP.CARGO_INFO_ID LEFT JOIN M_CARGO m ON t.CARGO_CODE = m.CARGO_CODE LEFT JOIN T_BUS_TRUST TBT ON t.TRUST_ID = TBT.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON t.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP_1 ON TFBCP_1.STATUS = '1' AND TFBCP_1.BUS_TRUST_ID = t.TRUST_ID LEFT JOIN (SELECT TBTC.ID, TBTC.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, CASE WHEN TBT2.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE TBT2.SHIP_NAME || '_' || TDSI2.VOYAGE END "shipNameVoyage" FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT2 ON TBTC.TRUST_ID = TBT2.ID AND TBT2.TYPE = '装船' LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI2 ON TBT2.SHIPVOYAGE_ITEM_ID = TDSI2.ID GROUP BY TBTC.ID, TBTC.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, TBT2.SHIP_NAME, TDSI2.VOYAGE ) TEMP ON t.ID = TEMP.CARGO_INFO_ID LEFT JOIN T_BUS_TRUST_CARGO TBTC ON t.ID = TBTC.CARGO_INFO_ID LEFT JOIN T_BUS_TRUST TBT2 ON TBTC.TRUST_ID = TBT2.ID
t.IS_LOGOUT = '20' AND t.IS_CLEAR = '0'
AND CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TEMP.SHIPVOYAGE_ITEM_ID ELSE t.SHIPVOYAGE_ITEM_ID END = #{shipvoyageItemId}
and t.SHIPVOYAGE_ID = #{shipvoyageId}
and t.SCN = #{scn}
and (t.IS_LOGOUT = #{isLogout} or t.IS_LOGOUT is null)
and t.IS_RELEASE = #{isRelease}
and t.IS_PRE_PAY = #{isPrePay}
and TBTC.BUSINESS_NO LIKE #{businessNoLike}
and t.CARGO_INFO_NO LIKE #{cargoInfoNo_like}
and t.CONTRACT_CODE LIKE #{contractCode_like}
and t.CARGO_OWNER_ID = #{cargoOwnerId}
and t.CARGO_OWNER_NAME = #{cargoOwnerName}
and t.CARGO_AGENT_ID = #{cargoAgentId}
and t.CARGO_AGENT_NAME = #{cargoAgentName}
and t.CARGO_CODE = #{cargoCode}
and t.CARGO_NAME LIKE #{cargoNameLike,jdbcType=VARCHAR}
and t.TRADE_TYPE = #{tradeType}
and t.PACKING_CODE = #{packingCode}
and t.PACKING_NAME = #{packingName}
and t.COMPANY_ID = #{companyId}
and t.COMPANY_NAME = #{companyName}
and t.PARENT_ID = #{parentId}
and t.ROOT_ID = #{rootId}
and t.IS_CLEAR = #{isClear} OR IS_CLEAR IS NULL
and m.WORK_TYPE = #{workType,jdbcType=VARCHAR}
and TFBCP.PREPAYMENT_CODE = #{prepaymentCode,jdbcType=VARCHAR}
and to_char(t.CREATE_TIME,'YYYY-MM-DD') >= #{startDate,jdbcType=VARCHAR}
and to_char(t.CREATE_TIME,'YYYY-MM-DD') < #{endDate,jdbcType=VARCHAR}
GROUP BY TFBCP.ID, TFBCP.PREPAYMENT_CODE, TFBCP.STATUS, t.ID, t.SHIPVOYAGE_ID, t.SHIPVOYAGE_ITEM_ID, t.SCN, t.SHIP_NAME, t.CARGO_INFO_NO, t.CARGO_OWNER_ID, t.CARGO_OWNER_NAME, t.CARGO_AGENT_ID, t.CARGO_AGENT_NAME, t.CARGO_CODE, t.CARGO_NAME, t.TRADE_TYPE, t.PACKING_CODE, t.PACKING_NAME, t.COMPANY_ID, t.COMPANY_NAME, t.IS_CLEAR, t.VOYAGE, t.RESIDUE_STORAGE, t.TRANSFER_DATE, m.TALLY, TBT.TYPE, TDSI.VOYAGE, t.IS_TOS, m.WORK_TYPE, t.IS_LOGOUT, t.IS_PRE_PAY, t.IS_RELEASE, t.CREATE_TIME, t.RELEASE_REMARK, t.REAL_CLEAR_DATE
HAVING CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END LIKE #{shipName_like}
AND CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END LIKE #{voyage_like}
HAVING CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END LIKE #{voyage_like}
ORDER BY CREATE_TIME DESC
